import loadPicture, { loadResource } from "./photoloader.ts";
import { displayCategory, displayPicture, displayComments } from "./ui.ts";


function getPicture(id: number) : void {
    loadPicture(id)
        .then((data) => {
            displayPicture(data);
            getCategory(data)
                .then( (categorie) => {
                    displayCategory(categorie);
                });
            getComments(data).then( (comments) => {
                    displayComments(comments);
                });
        }).catch( (err : unknown) => {
            if(err instanceof Error){
                console.log(err.message);
            }
        });
}

getPicture(
    window.location.hash
        ? Number(window.location.hash.substr(1))
        : 105
);

// ne pas mettre any, mettre des types dans les data: et dans les promises
function getCategory(data : any) : Promise<any> {
    console.log(data.links.categorie.href);
    return loadResource(data.links.categorie.href);
}

function getComments(data : any) : Promise<any> {
    return loadResource(data.links.comments.href);
}