import api from "./config.ts";

export default function loadPicture(idPicture: number): Promise<any> {
    let url = api + "/photos/" + idPicture;

    return fetch(url, {credentials: 'include'})
            .then( (response: Response) => {
        if(!response.ok){
            return Promise.reject(
                new Error("Erreur HTTP : " + response.status)
            );
        }
        return response.json();
    }).catch( (err: unknown) => {
        if(err instanceof Error){
            console.log(err.message);
        }
        return Promise.reject(err);
    });
}

export function loadResource(uri : string) : Promise<any> {
    return fetch("https://webetu.iutnc.univ-lorraine.fr" + uri, {credentials: 'include'})
    .then( (response : Response) => {
        if(!response.ok){
            return Promise.reject(new Error(response.statusText));
        }
        return response.json();
    }).catch( (err : unknown) => {
        if(err instanceof Error){
            console.log(err.message);
        }
        return Promise.reject(err);
    });
}