declare const Handlebars : any;

export function displayPicture(data : any) : void {

    const templateElement = document.querySelector("#photoTemplate") as HTMLScriptElement;

    const templateSource = templateElement.innerHTML;
    const template = Handlebars.compile(templateSource);
    const html = template(data);
    const photoSection = document.querySelector("#la_photo") as HTMLElement;

    photoSection.innerHTML = html;
}

export function displayCategory(data : any) : void {

    const categorie = document.querySelector("#la_categorie") as HTMLElement;

    console.log(data);

    categorie.innerHTML = "categorie : " + data.categorie.nom;
}


export function displayComments(data : any) : void {
    const liste = document.querySelector("#les_commentaires") as HTMLElement;
    liste.innerHTML = "";
    data.comments.forEach( (comment : any) => {
        liste.innerHTML +=
            "<li>"
            + comment.pseudo
            + " : "
            + comment.content
            + "</li>";
    });
}